defmodule BankAccount do
  @moduledoc """
  A bank account that supports access from multiple processes.
  """

  use GenServer

  ## Callbacks

  @impl true
  def init(_args) do
    {:ok, 0}
  end

  @impl true
  def handle_call(:balance, _from, balance) do
    {:reply, balance, balance}
  end

  @impl true
  def handle_call({:deposit, amount}, _from, balance) do
    if amount <= 0 do
      {:reply, {:error, :amount_must_be_positive}, balance}
    else
      {:reply, :ok, balance + amount}
    end
  end

  @impl true
  def handle_call({:withdraw, amount}, _from, balance) do
    cond do
      amount <= 0 ->
        {:reply, {:error, :amount_must_be_positive}, balance}

      balance < amount ->
        {:reply, {:error, :not_enough_balance}, balance}

      true ->
        {:reply, :ok, balance - amount}
    end
  end

  @impl true
  def handle_call(:close, _from, balance) do
    # We stop normally and return :stopped to the caller.
    {:stop, :normal, :stopped, balance}
  end

  ## Interface for tests

  @typedoc """
  An account handle.
  """
  @opaque account :: pid

  @doc """
  Open the bank account, making it available for further operations.
  """
  @spec open() :: account
  def open() do
    {:ok, pid} = GenServer.start_link(__MODULE__, [], [])
    pid
  end

  @doc """
  Close the bank account, making it unavailable for further operations.
  """
  @spec close(account) :: any
  def close(account) do
    GenServer.stop(account)
  end

  @doc """
  Get the account's balance.
  """
  @spec balance(account) :: integer | {:error, :account_closed}
  def balance(account) do
    if Process.alive?(account) do
      GenServer.call(account, :balance)
    else
      {:error, :account_closed}
    end
  end

  @doc """
  Add the given amount to the account's balance.
  """
  @spec deposit(account, integer) :: :ok | {:error, :account_closed | :amount_must_be_positive}
  def deposit(account, amount) do
    if Process.alive?(account) do
      GenServer.call(account, {:deposit, amount})
    else
      {:error, :account_closed}
    end
  end

  @doc """
  Subtract the given amount from the account's balance.
  """
  @spec withdraw(account, integer) ::
          :ok | {:error, :account_closed | :amount_must_be_positive | :not_enough_balance}
  def withdraw(account, amount) do
    if Process.alive?(account) do
      GenServer.call(account, {:withdraw, amount})
    else
      {:error, :account_closed}
    end
  end
end

defmodule CircularBuffer do
  use GenServer

  @moduledoc """
  An API to a stateful process that fills and empties a circular buffer
  """

  # CLIENT API

  @doc """
  Create a new buffer of a given capacity
  """
  @spec new(capacity :: integer) :: {:ok, pid}
  def new(capacity) do
    GenServer.start_link(__MODULE__, capacity, [])
  end

  @doc """
  Read the oldest entry in the buffer, fail if it is empty
  """
  @spec read(buffer :: pid) :: {:ok, any} | {:error, atom}
  def read(buffer) do
    GenServer.call(buffer, :read)
  end

  @doc """
  Write a new item in the buffer, fail if is full
  """
  @spec write(buffer :: pid, item :: any) :: :ok | {:error, atom}
  def write(buffer, item) do
    GenServer.call(buffer, {:write, item})
  end

  @doc """
  Write an item in the buffer, overwrite the oldest entry if it is full
  """
  @spec overwrite(buffer :: pid, item :: any) :: :ok
  def overwrite(buffer, item) do
    GenServer.cast(buffer, {:overwrite, item})
  end

  @doc """
  Clear the buffer
  """
  @spec clear(buffer :: pid) :: :ok
  def clear(buffer) do
    GenServer.cast(buffer, :clear)
  end

  # DATA STRUCTURE
  # Essentially a deque made out of two lists, one for new input (write, overwrite)
  # and one for output (read), and keeping track of the size and capacity.

  defstruct [:capacity, size: 0, input: [], output: []]

  defp new_buffer(capacity), do: {:ok, %CircularBuffer{capacity: capacity}}

  defp read_buffer(%CircularBuffer{size: 0} = buffer), do: {{:error, :empty}, buffer}

  defp read_buffer(%CircularBuffer{size: size, output: [out | output]} = buffer),
    do: {{:ok, out}, %{buffer | size: size - 1, output: output}}

  defp read_buffer(%CircularBuffer{input: input} = buffer),
    do: read_buffer(%{buffer | input: [], output: Enum.reverse(input)})

  defp write_buffer(%CircularBuffer{size: capacity, capacity: capacity} = buffer, _item),
    do: {{:error, :full}, buffer}

  defp write_buffer(%CircularBuffer{size: size, input: input} = buffer, item),
    do: {:ok, %{buffer | size: size + 1, input: [item | input]}}

  defp overwrite_buffer(%CircularBuffer{size: capacity, capacity: capacity} = buffer, item) do
    {_, smaller_buffer} = read_buffer(buffer)
    write_buffer(smaller_buffer, item)
  end

  defp overwrite_buffer(buffer, item), do: write_buffer(buffer, item)

  defp clear_buffer(%CircularBuffer{capacity: capacity}), do: %CircularBuffer{capacity: capacity}

  # SERVER API

  @impl true
  def init(capacity) do
    new_buffer(capacity)
  end

  @impl true
  def handle_call(:read, _from, buffer) do
    {reply, buffer} = read_buffer(buffer)
    {:reply, reply, buffer}
  end

  @impl true
  def handle_call({:write, item}, _from, buffer) do
    {reply, buffer} = write_buffer(buffer, item)
    {:reply, reply, buffer}
  end

  @impl true
  def handle_cast({:overwrite, item}, buffer) do
    {_reply, buffer} = overwrite_buffer(buffer, item)
    {:noreply, buffer}
  end

  @impl true
  def handle_cast(:clear, buffer) do
    {:noreply, clear_buffer(buffer)}
  end
end

defmodule ComplexNumbers do
  @typedoc """
  In this module, complex numbers are represented as a tuple-pair containing the real and
  imaginary parts.
  For example, the real number `1` is `{1, 0}`, the imaginary number `i` is `{0, 1}` and
  the complex number `4+3i` is `{4, 3}'.
  """
  @type complex :: {number, number}

  @doc """
  Return the real part of a complex number
  """
  @spec real(a :: complex) :: number
  def real({real, _im}), do: real

  @doc """
  Return the imaginary part of a complex number
  """
  @spec imaginary(a :: complex) :: number
  def imaginary({_real, im}), do: im

  @doc """
  Multiply two complex numbers, or a real and a complex number
  """
  @spec mul(a :: complex | number, b :: complex | number) :: complex
  def mul({a, b}, {c, d}), do: {a * c - b * d, b * c + a * d}
  def mul(a, b), do: mul(to_complex(a), to_complex(b))

  @doc """
  Add two complex numbers, or a real and a complex number
  """
  @spec add(a :: complex | number, b :: complex | number) :: complex
  def add({a, b}, {c, d}), do: {a + c, b + d}
  def add(a, b), do: add(to_complex(a), to_complex(b))

  @doc """
  Subtract two complex numbers, or a real and a complex number
  """
  @spec sub(a :: complex | number, b :: complex | number) :: complex
  def sub({a, b}, {c, d}), do: {a - c, b - d}
  def sub(a, b), do: sub(to_complex(a), to_complex(b))

  @doc """
  Divide two complex numbers, or a real and a complex number
  """
  @spec div(a :: complex | number, b :: complex | number) :: complex
  def div({a, b}, {c, d}) do
    {(a * c + b * d) / (c * c + d * d), (b * c - a * d) / (c * c + d * d)}
  end

  def div(a, b), do: __MODULE__.div(to_complex(a), to_complex(b))

  @doc """
  Absolute value of a complex number
  """
  @spec abs(a :: complex) :: number
  def abs({a, b}), do: :math.sqrt(a * a + b * b)

  @doc """
  Conjugate of a complex number
  """
  @spec conjugate(a :: complex) :: complex
  def conjugate({a, b}), do: {a, -b}

  @doc """
  Exponential of a complex number
  """
  @spec exp(a :: complex) :: complex
  def exp({a, b}), do: {:math.exp(a) * :math.cos(b), :math.exp(a) * :math.sin(b)}

  defp to_complex({a, b}), do: {a, b}
  defp to_complex(a), do: {a, 0}
end

defmodule CustomSet do
  defstruct map: Map.new()

  @opaque t :: %__MODULE__{map: map}

  @spec new(Enum.t()) :: t
  def new(enumerable) do
    %CustomSet{map: Map.new(enumerable, fn x -> {x, true} end)}
  end

  @spec empty?(t) :: boolean
  def empty?(%CustomSet{map: map}) do
    Map.keys(map) |> Enum.empty?()
  end

  @spec contains?(t, any) :: boolean
  def contains?(%CustomSet{map: map}, element) do
    Map.has_key?(map, element)
  end

  @spec subset?(t, t) :: boolean
  def subset?(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    if map_size(map1) <= map_size(map2) do
      Map.keys(map1) |> do_subset?(map2)
    else
      false
    end
  end

  defp do_subset?([], _), do: true

  defp do_subset?([key | rest], map2) do
    if Map.has_key?(map2, key) do
      do_subset?(rest, map2)
    else
      false
    end
  end

  @spec disjoint?(t, t) :: boolean
  def disjoint?(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    total_size = map_size(map1) + map_size(map2)
    merged_size = map_size(Map.merge(map1, map2))
    total_size == merged_size
  end

  @spec equal?(t, t) :: boolean
  def equal?(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    Map.equal?(map1, map2)
  end

  @spec add(t, any) :: t
  def add(%CustomSet{map: map}, element) do
    %CustomSet{map: Map.put(map, element, true)}
  end

  @spec intersection(t, t) :: t
  def intersection(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    {map1, map2} = order_by_size(map1, map2)
    %CustomSet{map: Map.take(map2, Map.keys(map1))}
  end

  defp order_by_size(map1, map2) when map_size(map1) > map_size(map2), do: {map2, map1}
  defp order_by_size(map1, map2), do: {map1, map2}

  @spec difference(t, t) :: t
  def difference(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    %CustomSet{map: Map.drop(map1, Map.keys(map2))}
  end

  @spec union(t, t) :: t
  def union(%CustomSet{map: map1}, %CustomSet{map: map2}) do
    %CustomSet{map: Map.merge(map1, map2)}
  end
end

defmodule School do
  @moduledoc """
  Simulate students in a school.

  Each student is in a grade.
  """

  @type school :: map

  @doc """
  Create a new, empty school.
  """
  @spec new() :: school
  def new(), do: %{}

  @doc """
  Add a student to a particular grade in school.
  """
  @spec add(school, String.t(), integer) :: {:ok | :error, school}
  def add(school, name, grade) do
    if name in List.flatten(Map.values(school)) do
      {:error, school}
    else
      {:ok, Map.update(school, grade, [name], &[name | &1])}
    end
  end

  @doc """
  Return the names of the students in a particular grade, sorted alphabetically.
  """
  @spec grade(school, integer) :: [String.t()]
  def grade(school, grade) do
    Map.get(school, grade, [])
    |> Enum.sort()
  end

  @doc """
  Return the names of all the students in the school sorted by grade and name.
  """
  @spec roster(school) :: [String.t()]
  def roster(school) do
    school
    |> Enum.map(fn {grade, students} -> {grade, Enum.sort(students)} end)
    |> Enum.sort()
    |> Enum.map(fn {_grade, students} -> students end)
    |> Enum.concat()
  end
end

