defmodule ListOps do
  # Please don't use any external modules (especially List or Enum) in your
  # implementation. The point of this exercise is to create these basic
  # functions yourself. You may use basic Kernel functions (like `Kernel.+/2`
  # for adding numbers), but please do not use Kernel functions for Lists like
  # `++`, `--`, `hd`, `tl`, `in`, and `length`.

  @spec count(list) :: non_neg_integer
  def count(l), do: do_count(l, 0)

  defp do_count([], acc), do: acc
  defp do_count([_ | t], acc), do: do_count(t, acc + 1)

  @spec reverse(list) :: list
  def reverse(l), do: do_reverse(l, [])

  defp do_reverse([], acc), do: acc
  defp do_reverse([h | t], acc), do: do_reverse(t, [h | acc])

  @spec map(list, (any -> any)) :: list
  def map(l, f), do: do_map(l, f, []) |> reverse()

  defp do_map([], _, acc), do: acc
  defp do_map([h | t], f, acc), do: do_map(t, f, [f.(h) | acc])

  @spec filter(list, (any -> as_boolean(term))) :: list
  def filter(l, f), do: do_filter(l, f, []) |> reverse()

  defp do_filter([], _, acc), do: acc

  defp do_filter([h | t], f, acc) do
    if f.(h) do
      do_filter(t, f, [h | acc])
    else
      do_filter(t, f, acc)
    end
  end

  @type acc :: any
  @spec foldl(list, acc, (any, acc -> acc)) :: acc
  def foldl([], acc, _), do: acc
  def foldl([h | t], acc, f), do: foldl(t, f.(h, acc), f)

  @spec foldr(list, acc, (any, acc -> acc)) :: acc
  def foldr([], acc, _), do: acc
  def foldr([h | t], acc, f), do: f.(h, foldr(t, acc, f))

  @spec append(list, list) :: list
  def append(a, b), do: do_append(reverse(a), b)

  defp do_append([], b), do: b
  defp do_append([h | t], b), do: do_append(t, [h | b])

  @spec concat([[any]]) :: [any]
  def concat(ll), do: reverse(ll) |> foldl([], &append/2)
end

defmodule Matrix do
  defstruct matrix: nil, transposed_matrix: nil

  @doc """
  Convert an `input` string, with rows separated by newlines and values
  separated by single spaces, into a `Matrix` struct.
  """
  @spec from_string(input :: String.t()) :: %Matrix{}
  def from_string(input) do
    rows =
      input
      |> String.split("\n", trim: true)
      |> Enum.map(&parse_line/1)

    %Matrix{
      matrix: rows,
      transposed_matrix: rows |> Enum.zip() |> Enum.map(&Tuple.to_list/1)
    }
  end

  defp parse_line(input_line) do
    input_line
    |> String.split(" ", trim: true)
    |> Enum.map(&String.to_integer/1)
  end

  @doc """
  Write the `matrix` out as a string, with rows separated by newlines and
  values separated by single spaces.
  """
  @spec to_string(matrix :: %Matrix{}) :: String.t()
  def to_string(%Matrix{matrix: rows}) do
    rows
    |> Enum.map(&join_row/1)
    |> Enum.join("\n")
  end

  defp join_row(row), do: Enum.join(row, " ")

  @doc """
  Given a `matrix`, return its rows as a list of lists of integers.
  """
  @spec rows(matrix :: %Matrix{}) :: list(list(integer))
  def rows(%Matrix{matrix: rows}), do: rows

  @doc """
  Given a `matrix` and `index`, return the row at `index`.
  """
  @spec row(matrix :: %Matrix{}, index :: integer) :: list(integer)
  def row(%Matrix{matrix: rows}, index), do: Enum.at(rows, index - 1)

  @doc """
  Given a `matrix`, return its columns as a list of lists of integers.
  """
  @spec columns(matrix :: %Matrix{}) :: list(list(integer))
  def columns(%Matrix{transposed_matrix: cols}), do: cols

  @doc """
  Given a `matrix` and `index`, return the column at `index`.
  """
  @spec column(matrix :: %Matrix{}, index :: integer) :: list(integer)
  def column(%Matrix{transposed_matrix: cols}, index), do: Enum.at(cols, index - 1)
end

defmodule Pov do
  # Structs and types

  @typedoc """
  A tree, which is made of a node with several branches
  """
  @type tree :: {any, [tree]}

  defmodule Crumb do
    defstruct [:parent, left_siblings: [], right_siblings: []]
    @type t :: %Crumb{parent: any, left_siblings: [Pov.tree()], right_siblings: [Pov.tree()]}
  end

  defmodule Zipper do
    defstruct [:focus, genealogy: []]
    @type t :: %Zipper{focus: Pov.tree(), genealogy: [Crumb.t()]}
  end

  # Core functions

  @doc """
  Reparent a tree on a selected node.
  """
  @spec from_pov(tree :: tree, node :: any) :: {:ok, tree} | {:error, atom}
  def from_pov(tree, node) do
    case tree |> zip |> search(node) do
      {:ok, zipper} -> {:ok, reparent(zipper)}
      _ -> {:error, :nonexistent_target}
    end
  end

  @doc """
  Finds a path between two nodes
  """
  @spec path_between(tree :: tree, from :: any, to :: any) :: {:ok, [any]} | {:error, atom}
  def path_between(tree, from, to) do
    case tree |> zip |> search(from) do
      {:ok, zipper} ->
        case zipper |> reparent |> zip |> search(to) do
          {:ok, zipper_path} -> {:ok, get_path(zipper_path)}
          _ -> {:error, :nonexistent_destination}
        end

      _ ->
        {:error, :nonexistent_source}
    end
  end

  defp search(%Zipper{focus: {node, _children}} = zipper, node), do: {:ok, zipper}

  defp search(%Zipper{} = zipper, node) do
    case zipper |> down |> search(node) do
      {:ok, z} -> {:ok, z}
      _ -> zipper |> right |> search(node)
    end
  end

  defp search(nil, _node), do: nil

  defp reparent(%Zipper{focus: tree, genealogy: []}), do: tree

  defp reparent(%Zipper{
         focus: {node, children},
         genealogy: [
           %Crumb{parent: parent, left_siblings: left, right_siblings: right} | grandparent
         ]
       }) do
    {node, [reparent(%Zipper{focus: {parent, left ++ right}, genealogy: grandparent}) | children]}
  end

  defp get_path(%Zipper{focus: {node, _children}, genealogy: genealogy}) do
    parents = Enum.map(genealogy, fn %Crumb{parent: parent} -> parent end)

    Enum.reverse([node | parents])
  end

  # Zipper navigation

  defp zip(tree), do: %Zipper{focus: tree}

  defp down(%Zipper{focus: {value, [child | children]}, genealogy: genealogy}) do
    %Zipper{
      focus: child,
      genealogy: [%Crumb{parent: value, right_siblings: children} | genealogy]
    }
  end

  defp down(_zipper), do: nil

  defp right(%Zipper{
         focus: tree,
         genealogy: [
           %Crumb{left_siblings: left, right_siblings: [right | righties]} = crumb | grandparents
         ]
       }) do
    %Zipper{
      focus: right,
      genealogy: [
        %Crumb{crumb | left_siblings: [tree | left], right_siblings: righties} | grandparents
      ]
    }
  end

  defp right(_zipper), do: nil
end

defmodule Prism do
  @doc """
  Finds the sequence of prisms that the laser will hit.
  """

  @type start :: %{angle: number(), x: number(), y: number()}
  @type prism :: %{id: integer(), angle: number(), x: number(), y: number()}

  @spec find_sequence(prisms :: [prism()], start :: start()) :: [integer()]
  def find_sequence(prisms, start) do
    find_next_prism(start, prisms, [])
  end

  @precision 0.01
  defp find_next_prism(start, prisms, sequence) do
    next_prism =
      prisms
      |> Enum.filter(fn %{x: x, y: y} ->
        different_prism? = x != start.x or y != start.y

        angle_to_prism = :math.atan2(y - start.y, x - start.x) / :math.pi() * 180
        angle_difference = abs(:math.fmod(angle_to_prism - start.angle, 360))

        pointing_to_prism? =
          angle_difference < @precision or 360 - angle_difference < @precision

        different_prism? and pointing_to_prism?
      end)
      |> Enum.min_by(
        fn %{x: x, y: y} -> (x - start.x) ** 2 + (y - start.y) ** 2 end,
        &<=/2,
        fn -> nil end
      )

    case next_prism do
      nil ->
        Enum.reverse(sequence)

      %{id: id, angle: angle, x: x, y: y} ->
        next_start = %{angle: start.angle + angle, x: x, y: y}
        find_next_prism(next_start, prisms, [id | sequence])
    end
  end
end

defmodule ProteinTranslation do
  @doc """
  Given an RNA string, return a list of proteins specified by codons, in order.
  """
  @spec of_rna(String.t()) :: {:ok, list(String.t())} | {:error, String.t()}
  def of_rna(rna) do
    translate_rna(rna, [])
  end

  @doc """
  Given a codon, return the corresponding protein

  UGU -> Cysteine
  UGC -> Cysteine
  UUA -> Leucine
  UUG -> Leucine
  AUG -> Methionine
  UUU -> Phenylalanine
  UUC -> Phenylalanine
  UCU -> Serine
  UCC -> Serine
  UCA -> Serine
  UCG -> Serine
  UGG -> Tryptophan
  UAU -> Tyrosine
  UAC -> Tyrosine
  UAA -> STOP
  UAG -> STOP
  UGA -> STOP
  """
  @spec of_codon(String.t()) :: {:ok, String.t()} | {:error, String.t()}
  def of_codon(codon) do
    translate_codon(codon)
  end

  @codons %{
    "Methionine" => ~w(AUG),
    "Phenylalanine" => ~w(UUU UUC),
    "Leucine" => ~w(UUA UUG),
    "Serine" => ~w(UCU UCC UCA UCG),
    "Tyrosine" => ~w(UAU UAC),
    "Cysteine" => ~w(UGU UGC),
    "Tryptophan" => ~w(UGG)
  }
  @stop ~w(UAA UAG UGA)

  defp translate_rna("", results), do: {:ok, Enum.reverse(results)}

  for codon <- @stop do
    defp translate_rna(unquote(codon) <> _rest, results), do: {:ok, Enum.reverse(results)}
    defp translate_codon(unquote(codon)), do: {:ok, "STOP"}
  end

  for {protein, codons} <- @codons,
      codon <- codons do
    defp translate_rna(unquote(codon) <> rest, results),
      do: translate_rna(rest, [unquote(protein) | results])

    defp translate_codon(unquote(codon)), do: {:ok, unquote(protein)}
  end

  defp translate_rna(_, _), do: {:error, "invalid RNA"}
  defp translate_codon(_), do: {:error, "invalid codon"}
end

defmodule RationalNumbers do
  @type rational :: {integer, integer}

  @doc """
  Add two rational numbers
  """
  @spec add(a :: rational, b :: rational) :: rational
  def add({a, b}, {c, d}), do: {a * d + c * b, b * d} |> reduce

  @doc """
  Subtract two rational numbers
  """
  @spec subtract(a :: rational, b :: rational) :: rational
  def subtract(a, {x, y}), do: add(a, {-x, y})

  @doc """
  Multiply two rational numbers
  """
  @spec multiply(a :: rational, b :: rational) :: rational
  def multiply({a, b}, {c, d}), do: {a * c, b * d} |> reduce

  @doc """
  Divide two rational numbers
  """
  @spec divide_by(num :: rational, den :: rational) :: rational
  def divide_by(num, {a, b}), do: multiply(num, {b, a})

  @doc """
  Absolute value of a rational number
  """
  @spec abs(a :: rational) :: rational
  def abs({a, b}), do: {Kernel.abs(a), Kernel.abs(b)} |> reduce

  @doc """
  Exponentiation of a rational number by an integer
  """
  @spec pow_rational(a :: rational, n :: integer) :: rational
  def pow_rational({a, b}, n) when n < 0, do: pow_rational({b, a}, -n)

  def pow_rational({a, b}, n),
    do: {:math.pow(a, n) |> round, :math.pow(b, n) |> round} |> reduce

  @doc """
  Exponentiation of a real number by a rational number
  """
  @spec pow_real(x :: float, n :: rational) :: float
  def pow_real(x, {a, b}), do: :math.pow(x, a / b)

  @doc """
  Reduce a rational number to its lowest terms
  """
  @spec reduce(a :: rational) :: rational
  def reduce({a, b}) when b < 0, do: reduce({-a, -b})

  def reduce({a, b}) do
    gcd = Integer.gcd(a, b)
    {div(a, gcd), div(b, gcd)}
  end
end

defmodule ResistorColorTrio do
  @colors %{
    black: 0,
    brown: 1,
    red: 2,
    orange: 3,
    yellow: 4,
    green: 5,
    blue: 6,
    violet: 7,
    grey: 8,
    white: 9
  }

  @doc """
  Calculate the resistance value in ohms from resistor colors
  """
  @spec label(colors :: [atom]) :: {number, :ohms | :kiloohms | :megaohms | :gigaohms}
  def label([a, b, c | _rest]) do
    value = (10 * @colors[a] + @colors[b]) * round(:math.pow(10, @colors[c]))

    cond do
      value >= 1_000_000_000 ->
        {div(value, 1_000_000_000), :gigaohms}

      value >= 1_000_000 ->
        {div(value, 1_000_000), :megaohms}

      value >= 1_000 ->
        {div(value, 1_000), :kiloohms}

      true ->
        {value, :ohms}
    end
  end
end

defmodule RobotSimulator do
  @type robot() :: any()
  @type direction() :: :north | :east | :south | :west
  @type position() :: {integer(), integer()}

  defstruct direction: nil, position: nil

  @valid_directions [:north, :east, :south, :west]

  @doc """
  Create a Robot Simulator given an initial direction and position.

  Valid directions are: `:north`, `:east`, `:south`, `:west`
  """
  @spec create(direction, position) :: robot() | {:error, String.t()}
  def create(direction \\ :north, position \\ {0, 0}) do
    %RobotSimulator{} |> place(position) |> orient(direction)
  end

  @doc """
  Simulate the robot's movement given a string of instructions.

  Valid instructions are: "R" (turn right), "L", (turn left), and "A" (advance)
  """
  @spec simulate(robot, instructions :: String.t()) :: robot() | {:error, String.t()}
  def simulate(%RobotSimulator{} = robot, instructions) do
    instructions |> String.graphemes() |> Enum.reduce(robot, &move/2)
  end

  @spec position(robot) :: position()
  def position(%RobotSimulator{position: pos}), do: pos

  @spec direction(robot) :: direction()
  def direction(%RobotSimulator{direction: dir}), do: dir

  defp orient(%RobotSimulator{} = robot, direction) when direction in @valid_directions do
    %{robot | direction: direction}
  end

  defp orient({:error, _} = error, _), do: error
  defp orient(_, _), do: {:error, "invalid direction"}

  defp place(%RobotSimulator{} = robot, {x, y} = position) when is_integer(x) and is_integer(y) do
    %{robot | position: position}
  end

  defp place(_, _), do: {:error, "invalid position"}

  defp move("R", %RobotSimulator{direction: direction} = robot),
    do: robot |> orient(direction |> rotate_right)

  defp move("L", %RobotSimulator{direction: direction} = robot),
    do: robot |> orient(direction |> rotate_left)

  defp move("A", %RobotSimulator{direction: :north, position: {x, y}} = robot),
    do: robot |> place({x, y + 1})

  defp move("A", %RobotSimulator{direction: :east, position: {x, y}} = robot),
    do: robot |> place({x + 1, y})

  defp move("A", %RobotSimulator{direction: :south, position: {x, y}} = robot),
    do: robot |> place({x, y - 1})

  defp move("A", %RobotSimulator{direction: :west, position: {x, y}} = robot),
    do: robot |> place({x - 1, y})

  defp move(_, {:error, _} = error), do: error
  defp move(_, _), do: {:error, "invalid instruction"}

  for [curr, right] <-
        @valid_directions |> Stream.cycle() |> Enum.take(5) |> Enum.chunk_every(2, 1) do
    defp rotate_right(unquote(curr)), do: unquote(right)
    defp rotate_left(unquote(right)), do: unquote(curr)
  end
end

defmodule Satellite do
  @typedoc """
  A tree, which can be empty, or made from a left branch, a node and a right branch
  """
  @type tree :: {} | {tree, any, tree}

  @doc """
  Build a tree from the elements given in a pre-order and in-order style
  """
  @spec build_tree(preorder :: [any], inorder :: [any]) :: {:ok, tree} | {:error, String.t()}

  def build_tree(preorder, inorder) do
    p_length = length(preorder)
    i_length = length(inorder)
    p_set = MapSet.new(preorder)
    i_set = MapSet.new(inorder)

    cond do
      p_length != i_length -> {:error, "traversals must have the same length"}
      p_set != i_set -> {:error, "traversals must have the same elements"}
      p_length != MapSet.size(p_set) -> {:error, "traversals must contain unique items"}
      true -> {:ok, do_build_tree(preorder, inorder)}
    end
  end

  defp do_build_tree([], []), do: {}

  defp do_build_tree([root | preorder], inorder) do
    {in_left, in_right, pre_left, pre_right} = split(root, inorder, preorder)

    {do_build_tree(pre_left, in_left), root, do_build_tree(pre_right, in_right)}
  end

  defp split(root, [root | inorder], preorder), do: {[], inorder, [], preorder}

  defp split(root, [i | inorder], [p | preorder]) do
    {in_left, in_right, pre_left, pre_right} = split(root, inorder, preorder)

    {[i | in_left], in_right, [p | pre_left], pre_right}
  end
end

defmodule LinkedList do
  @opaque t :: tuple()

  @doc """
  Construct a new LinkedList
  """
  @spec new() :: t
  def new() do
    {}
  end

  @doc """
  Push an item onto a LinkedList
  """
  @spec push(t, any()) :: t
  def push(list, elem) do
    {elem, list}
  end

  @doc """
  Counts the number of elements in a LinkedList
  """
  @spec count(t) :: non_neg_integer()
  def count(list) do
    do_count(list, 0)
  end

  defp do_count({}, n), do: n
  defp do_count({_, t}, n), do: do_count(t, n + 1)

  @doc """
  Determine if a LinkedList is empty
  """
  @spec empty?(t) :: boolean()
  def empty?({}), do: true
  def empty?(_), do: false

  @doc """
  Get the value of a head of the LinkedList
  """
  @spec peek(t) :: {:ok, any()} | {:error, :empty_list}
  def peek({}), do: {:error, :empty_list}
  def peek({x, _}), do: {:ok, x}

  @doc """
  Get tail of a LinkedList
  """
  @spec tail(t) :: {:ok, t} | {:error, :empty_list}
  def tail({}), do: {:error, :empty_list}
  def tail({_, t}), do: {:ok, t}

  @doc """
  Remove the head from a LinkedList
  """
  @spec pop(t) :: {:ok, any(), t} | {:error, :empty_list}
  def pop({}), do: {:error, :empty_list}
  def pop({h, t}), do: {:ok, h, t}

  @doc """
  Construct a LinkedList from a stdlib List
  """
  @spec from_list(list()) :: t
  def from_list(list) do
    List.foldr(list, new(), &push(&2, &1))
  end

  @doc """
  Construct a stdlib List LinkedList from a LinkedList
  """
  @spec to_list(t) :: list()
  def to_list(list) do
    list |> do_to_list([]) |> Enum.reverse()
  end

  defp do_to_list({}, acc), do: acc
  defp do_to_list({h, t}, acc), do: do_to_list(t, [h | acc])

  @doc """
  Reverse a LinkedList
  """
  @spec reverse(t) :: t
  def reverse(list) do
    do_reverse(list, new())
  end

  defp do_reverse({}, acc), do: acc
  defp do_reverse({h, t}, acc), do: do_reverse(t, push(acc, h))
end

