defmodule SplitSecondStopwatch do
  @doc """
  A stopwatch that can be used to track lap times.
  """

  @type state :: :ready | :running | :stopped

  defmodule Stopwatch do
    @type t :: %Stopwatch{
            state: SplitSecondStopwatch.state(),
            current_lap: Time.t(),
            previous_laps: [Time.t()]
          }
    defstruct state: :ready, current_lap: ~T[00:00:00], previous_laps: []
  end

  @spec new() :: Stopwatch.t()
  def new() do
    %Stopwatch{}
  end

  @spec state(Stopwatch.t()) :: state()
  def state(%Stopwatch{state: state}) do
    state
  end

  @spec current_lap(Stopwatch.t()) :: Time.t()
  def current_lap(%Stopwatch{current_lap: current_lap}) do
    current_lap
  end

  @spec previous_laps(Stopwatch.t()) :: [Time.t()]
  def previous_laps(%Stopwatch{previous_laps: previous_laps}) do
    Enum.reverse(previous_laps)
  end

  @spec advance_time(Stopwatch.t(), Time.t()) :: Stopwatch.t()
  def advance_time(%Stopwatch{state: :running, current_lap: current_lap} = stopwatch, time) do
    current_lap = add_times(current_lap, time)
    %{stopwatch | current_lap: current_lap}
  end

  def advance_time(%Stopwatch{} = stopwatch, _time) do
    stopwatch
  end

  @spec total(Stopwatch.t()) :: Time.t()
  def total(%Stopwatch{current_lap: current_lap, previous_laps: previous_laps}) do
    Enum.reduce(previous_laps, current_lap, &add_times/2)
  end

  @spec start(Stopwatch.t()) :: Stopwatch.t() | {:error, String.t()}
  def start(%Stopwatch{state: :running}) do
    {:error, "cannot start an already running stopwatch"}
  end

  def start(%Stopwatch{} = stopwatch) do
    %{stopwatch | state: :running}
  end

  @spec stop(Stopwatch.t()) :: Stopwatch.t() | {:error, String.t()}
  def stop(%Stopwatch{state: :running} = stopwatch) do
    %{stopwatch | state: :stopped}
  end

  def stop(%Stopwatch{}) do
    {:error, "cannot stop a stopwatch that is not running"}
  end

  @spec lap(Stopwatch.t()) :: Stopwatch.t() | {:error, String.t()}
  def lap(%Stopwatch{state: :running} = stopwatch) do
    current_lap = ~T[00:00:00]
    previous_laps = [stopwatch.current_lap | stopwatch.previous_laps]

    %{stopwatch | current_lap: current_lap, previous_laps: previous_laps}
  end

  def lap(%Stopwatch{}) do
    {:error, "cannot lap a stopwatch that is not running"}
  end

  @spec reset(Stopwatch.t()) :: Stopwatch.t() | {:error, String.t()}
  def reset(%Stopwatch{state: :stopped}) do
    %Stopwatch{}
  end

  def reset(%Stopwatch{}) do
    {:error, "cannot reset a stopwatch that is not stopped"}
  end

  defp add_times(time1, time2) do
    {time2_in_seconds, _microseconds} = Time.to_seconds_after_midnight(time2)
    Time.add(time1, time2_in_seconds, :second)
  end
end

defmodule StateOfTicTacToe do
  @rows [[{0, 0}, {0, 1}, {0, 2}], [{1, 0}, {1, 1}, {1, 2}], [{2, 0}, {2, 1}, {2, 2}]]
  @columns [[{0, 0}, {1, 0}, {2, 0}], [{0, 1}, {1, 1}, {2, 1}], [{0, 2}, {1, 2}, {2, 2}]]
  @diagonals [[{0, 0}, {1, 1}, {2, 2}], [{0, 2}, {1, 1}, {2, 0}]]

  @doc """
  Determine the state a game of tic-tac-toe where X starts.
  """
  @spec game_state(board :: String.t()) :: {:ok, :win | :ongoing | :draw} | {:error, String.t()}
  def game_state(board) do
    board =
      for {line, row} <- board |> String.split("\n", trim: true) |> Enum.with_index(),
          {player, col} <- line |> to_charlist() |> Enum.with_index(),
          into: %{} do
        {{row, col}, player}
      end

    x_count = Enum.count(board, fn {_, c} -> c == ?X end)
    o_count = Enum.count(board, fn {_, c} -> c == ?O end)

    x_wins = wins?(board, ?X)
    o_wins = wins?(board, ?O)

    cond do
      x_count - o_count > 1 ->
        {:error, "Wrong turn order: X went twice"}

      o_count - x_count > 0 ->
        {:error, "Wrong turn order: O started"}

      x_wins and o_wins ->
        {:error, "Impossible board: game should have ended after the game was won"}

      x_wins or o_wins ->
        {:ok, :win}

      o_count == 4 ->
        {:ok, :draw}

      true ->
        {:ok, :ongoing}
    end
  end

  defp wins?(board, player) do
    Enum.any?(
      @rows ++ @columns ++ @diagonals,
      fn cells -> Enum.all?(cells, fn cell -> board[cell] == player end) end
    )
  end
end

defmodule Triangle do
  def kind(a, b, c), do: kind(Enum.sort([a, b, c]))

  defp kind([a, _, _]) when a <= 0, do: {:error, "all side lengths must be positive"}
  defp kind([a, b, c]) when a + b <= c, do: {:error, "side lengths violate triangle inequality"}
  defp kind([x, x, x]), do: {:ok, :equilateral}
  defp kind([x, x, _]), do: {:ok, :isosceles}
  defp kind([_, x, x]), do: {:ok, :isosceles}
  defp kind([_, _, _]), do: {:ok, :scalene}
end

defmodule WordSearch do
  defmodule Location do
    defstruct [:from, :to]

    @type t :: %Location{
            from: %{row: integer, column: integer},
            to: %{row: integer, column: integer}
          }
  end

  @doc """
  Find the start and end positions of words in a grid of letters.
  Row and column positions are 1 indexed.
  """
  @spec search(grid :: String.t(), words :: [String.t()]) :: %{String.t() => nil | Location.t()}
  def search(grid, words) do
    grid =
      String.split(grid, "\n")
      |> Enum.map(&to_charlist/1)

    {coord, starting_points} =
      for {row, r} <- Enum.with_index(grid, 1),
          {char, c} <- Enum.with_index(row, 1) do
        {char, %{row: r, column: c}}
      end
      |> Enum.reduce({%{}, %{}}, fn {char, pos}, {coord, starting_points} ->
        {Map.put(coord, pos, char), Map.update(starting_points, char, [pos], &[pos | &1])}
      end)

    Map.new(words, fn <<start, _::binary>> = word ->
      {word, search(word, starting_points[start], coord)}
    end)
  end

  defp search(_word, nil, _coord), do: nil

  defp search(word, starting_points, coord) do
    word_length = String.length(word)
    word = to_charlist(word)

    for point <- starting_points,
        path <- make_paths(point, word_length - 1),
        word == Enum.map(path, &coord[&1]) do
      %Location{from: List.first(path), to: List.last(path)}
    end
    |> Enum.reduce(nil, &||/2)
  end

  defp make_paths(%{row: r, column: c}, delta) do
    [
      for(i <- 0..delta, do: %{row: r + i, column: c}),
      for(i <- 0..delta, do: %{row: r - i, column: c}),
      for(i <- 0..delta, do: %{row: r, column: c + i}),
      for(i <- 0..delta, do: %{row: r, column: c - i}),
      for(i <- 0..delta, do: %{row: r + i, column: c + i}),
      for(i <- 0..delta, do: %{row: r + i, column: c - i}),
      for(i <- 0..delta, do: %{row: r - i, column: c + i}),
      for(i <- 0..delta, do: %{row: r - i, column: c - i})
    ]
  end
end

defmodule Zipper do
  @moduledoc """
  A binary tree zipper.

  `value` is the value of the focus.
  `left` is the left subtree of the focus.
  `right` is the right subtree of the focus.
  `trail` is the trail of the focus.

  The trail stores the path that a zipper has taken into the tree from the root
  and the alternative branches.
  """

  alias BinTree, as: BT
  alias __MODULE__, as: Z

  @type t :: %Z{
          value: any,
          left: BT.t() | nil,
          right: BT.t() | nil,
          trail: [{:left, any, BT.t()} | {:right, any, BT.t()}]
        }
  defstruct value: nil, left: nil, right: nil, trail: []

  @doc """
  Get a zipper focussed on the root node.
  """
  @spec from_tree(BT.t()) :: Z.t()
  def from_tree(%BT{value: v, left: l, right: r}) do
    %Z{value: v, left: l, right: r, trail: []}
  end

  @doc """
  Get the complete tree from a zipper.
  """
  @spec to_tree(Z.t()) :: BT.t()
  def to_tree(%Z{value: v, left: l, right: r, trail: t}) do
    do_to_tree(%BT{value: v, left: l, right: r}, t)
  end

  defp do_to_tree(b, []) do
    b
  end

  defp do_to_tree(b, [{:left, pv, pr} | pt]) do
    do_to_tree(%BT{value: pv, left: b, right: pr}, pt)
  end

  defp do_to_tree(b, [{:right, pv, pl} | pt]) do
    do_to_tree(%BT{value: pv, left: pl, right: b}, pt)
  end

  @doc """
  Get the value of the focus node.
  """
  @spec value(Z.t()) :: any
  def value(%Z{value: v}), do: v

  @doc """
  Get the left child of the focus node, if any.
  """
  @spec left(Z.t()) :: Z.t() | nil
  def left(%Z{left: nil}), do: nil

  def left(%Z{value: v, left: %BT{value: lv, left: ll, right: lr}, right: r, trail: zt}) do
    %Z{value: lv, left: ll, right: lr, trail: [{:left, v, r} | zt]}
  end

  @doc """
  Get the right child of the focus node, if any.
  """
  @spec right(Z.t()) :: Z.t() | nil
  def right(%Z{right: nil}), do: nil

  def right(%Z{value: v, left: l, right: %BT{value: rv, left: rl, right: rr}, trail: zt}) do
    %Z{value: rv, left: rl, right: rr, trail: [{:right, v, l} | zt]}
  end

  @doc """
  Get the parent of the focus node, if any.
  """
  @spec up(Z.t()) :: Z.t()
  def up(%Z{value: v, left: l, right: r, trail: t}) do
    case t do
      [] ->
        nil

      [{:left, pv, pr} | zt] ->
        %Z{value: pv, left: %BT{value: v, left: l, right: r}, right: pr, trail: zt}

      [{:right, pv, pl} | zt] ->
        %Z{value: pv, left: pl, right: %BT{value: v, left: l, right: r}, trail: zt}
    end
  end

  @doc """
  Set the value of the focus node.
  """
  @spec set_value(Z.t(), any) :: Z.t()
  def set_value(z, v), do: %{z | value: v}

  @doc """
  Replace the left child tree of the focus node.
  """
  @spec set_left(Z.t(), BT.t()) :: Z.t()
  def set_left(z, l), do: %{z | left: l}

  @doc """
  Replace the right child tree of the focus node.
  """
  @spec set_right(Z.t(), BT.t()) :: Z.t()
  def set_right(z, r), do: %{z | right: r}
end

defmodule Form do
  @moduledoc """
  A collection of loosely related functions helpful for filling out various forms at the city office.
  """

  @type address_map() :: %{street: String.t(), postal_code: String.t(), city: String.t()}
  @type address_tuple() :: {street :: String.t(), postal_code :: String.t(), city :: String.t()}
  @type address() :: address_map() | address_tuple()

  @doc """
  Generates a string of a given length.

  This string can be used to fill out a form field that is supposed to have no value.
  Such fields cannot be left empty because a malicious third party could fill them out with false data.
  """
  @spec blanks(non_neg_integer()) :: String.t()
  def blanks(n) do
    String.duplicate("X", n)
  end

  @doc """
  Splits the string into a list of uppercase letters.

  This is needed for form fields that don't offer a single input for the whole string,
  but instead require splitting the string into a predefined number of single-letter inputs.
  """
  @spec letters(String.t()) :: list(String.t())
  def letters(word) do
    word
    |> String.upcase()
    |> String.split("", trim: true)
  end

  @doc """
  Checks if the value has no more than the maximum allowed number of letters.

  This is needed to check that the values of fields do not exceed the maximum allowed length.
  It also tells you by how much the value exceeds the maximum.
  """
  @spec check_length(String.t(), non_neg_integer()) :: :ok | {:error, pos_integer()}
  def check_length(word, length) do
    diff = String.length(word) - length

    if diff <= 0 do
      :ok
    else
      {:error, diff}
    end
  end

  @doc """
  Formats the address as an uppercase multiline string.
  """
  @spec format_address(address()) :: String.t()
  def format_address(%{street: street, postal_code: postal_code, city: city}) do
    format_address({street, postal_code, city})
  end

  def format_address({street, postal_code, city}) do
    """
    #{String.upcase(street)}
    #{String.upcase(postal_code)} #{String.upcase(city)}
    """
  end
end

defmodule DancingDots.Animation do
  @type dot :: DancingDots.Dot.t()
  @type opts :: keyword
  @type error :: any
  @type frame_number :: pos_integer

  @callback init(opts :: opts) :: {:ok, opts} | {:error, error}
  @callback handle_frame(dot :: dot, n :: frame_number, opts :: opts) :: dot

  defmacro __using__(_) do
    quote do
      @behaviour DancingDots.Animation
      def init(opts), do: {:ok, opts}
      defoverridable init: 1
    end
  end
end

defmodule DancingDots.Flicker do
  use DancingDots.Animation

  @impl DancingDots.Animation
  def handle_frame(dot, frame_number, _opts) do
    opacity = if rem(frame_number, 4) == 0, do: dot.opacity / 2, else: dot.opacity
    %{dot | opacity: opacity}
  end
end

defmodule DancingDots.Zoom do
  use DancingDots.Animation

  @impl DancingDots.Animation
  def init(opts) do
    velocity = Keyword.get(opts, :velocity)

    if is_number(velocity) do
      {:ok, [velocity: velocity]}
    else
      {:error,
       "The :velocity option is required, and its value must be a number. Got: #{inspect(velocity)}"}
    end
  end

  @impl DancingDots.Animation
  def handle_frame(dot, frame_number, opts) do
    %{dot | radius: dot.radius + opts[:velocity] * (frame_number - 1)}
  end
end

defmodule TakeANumberDeluxe do
  use GenServer

  # Client API

  @spec start_link(keyword()) :: {:ok, pid()} | {:error, atom()}
  def start_link(init_arg) do
    GenServer.start_link(__MODULE__, init_arg)
  end

  @spec report_state(pid()) :: TakeANumberDeluxe.State.t()
  def report_state(machine) do
    GenServer.call(machine, :report_state)
  end

  @spec queue_new_number(pid()) :: {:ok, integer()} | {:error, atom()}
  def queue_new_number(machine) do
    GenServer.call(machine, :queue_new_number)
  end

  @spec serve_next_queued_number(pid(), integer() | nil) :: {:ok, integer()} | {:error, atom()}
  def serve_next_queued_number(machine, priority_number \\ nil) do
    GenServer.call(machine, {:serve_next_queued_number, priority_number})
  end

  @spec reset_state(pid()) :: :ok
  def reset_state(machine) do
    GenServer.cast(machine, :reset_state)
  end

  # Server callbacks

  @impl GenServer
  def init(init_arg) do
    min_number = Keyword.get(init_arg, :min_number)
    max_number = Keyword.get(init_arg, :max_number)
    auto_shutdown_timeout = Keyword.get(init_arg, :auto_shutdown_timeout, :infinity)

    case TakeANumberDeluxe.State.new(min_number, max_number, auto_shutdown_timeout) do
      {:ok, state} -> {:ok, state, auto_shutdown_timeout}
      {:error, error} -> {:stop, error}
    end
  end

  @impl GenServer
  def handle_call(:report_state, _from, state) do
    {:reply, state, state, state.auto_shutdown_timeout}
  end

  @impl GenServer
  def handle_call(:queue_new_number, _from, state) do
    case TakeANumberDeluxe.State.queue_new_number(state) do
      {:ok, new_number, new_state} ->
        {:reply, {:ok, new_number}, new_state, state.auto_shutdown_timeout}

      {:error, error} ->
        {:reply, {:error, error}, state, state.auto_shutdown_timeout}
    end
  end

  @impl GenServer
  def handle_call({:serve_next_queued_number, priority_number}, _from, state) do
    case TakeANumberDeluxe.State.serve_next_queued_number(state, priority_number) do
      {:ok, next_number, new_state} ->
        {:reply, {:ok, next_number}, new_state, state.auto_shutdown_timeout}

      {:error, error} ->
        {:reply, {:error, error}, state, state.auto_shutdown_timeout}
    end
  end

  @impl GenServer
  def handle_cast(:reset_state, state) do
    {:ok, state} =
      TakeANumberDeluxe.State.new(
        state.min_number,
        state.max_number,
        state.auto_shutdown_timeout
      )

    {:noreply, state, state.auto_shutdown_timeout}
  end

  @impl GenServer
  def handle_info(:timeout, state) do
    {:stop, :normal, state}
  end

  @impl GenServer
  def handle_info(_, state) do
    {:noreply, state, state.auto_shutdown_timeout}
  end
end
